class Solution:
    def sumOfLargestPrimes(self, s):
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        primes = set()
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                v = int(s[i:j])
                if is_prime(v):
                    primes.add(v)
        top = sorted(primes, reverse=True)[:3]
        return sum(top)

