class Solution:
    def sumOfLargestPrimes(self, s):
        def is_prime(x):
            if x < 2:
                return False
            if x % 2 == 0:
                return x == 2
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        seen = set()
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n + 1):
                v = int(s[i:j])
                if is_prime(v):
                    seen.add(v)
        return sum(sorted(seen, reverse=True)[:3])

