var sumOfLargestPrimes = function(s) {
    const isPrime = (x) => {
        if (x < 2n) return false;
        if (x % 2n === 0n) return x === 2n;
        for (let i = 3n; i * i <= x; i += 2n) {
            if (x % i === 0n) return false;
        }
        return true;
    };
    const seen = new Set();
    const n = s.length;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j <= n; j++) {
            const v = BigInt(s.slice(i, j));
            if (isPrime(v)) seen.add(v);
        }
    }
    const arr = [...seen].sort((a, b) => (a < b ? 1 : a > b ? -1 : 0));
    let total = 0n;
    for (let i = 0; i < Math.min(3, arr.length); i++) total += arr[i];
    return Number(total);
};
